import React, { useState, useEffect, useRef } from "react";
import { Link } from "react-router-dom";
import L from "leaflet";
import "leaflet/dist/leaflet.css";
import styles from "./PlanTripPage.module.css";
import { Route } from "@/types/route";
import { Stop } from "@/types/stop";
import { mockRoutes } from "../../lib/mocks/mockTripData";

interface RouteSegment {
  route: Route;
  fromStop: Stop;
  toStop: Stop;
  stops: Stop[];
}
interface RouteResult {
  segments: RouteSegment[];
  totalStops: number;
  transfers: number;
  startStop: Stop;
  endStop: Stop;
  walkingDistanceStart: number;
  walkingDistanceEnd: number;
}

const PlanTripPage: React.FC = () => {
  const [routes, setRoutes] = useState<Route[]>([]);
  const [stops, setStops] = useState<Stop[]>([]);
  const [fromLocation, setFromLocation] = useState<string>("");
  const [toLocation, setToLocation] = useState<string>("");
  const [fromCoords, setFromCoords] = useState<{lat: number, lng: number} | null>(null);
  const [toCoords, setToCoords] = useState<{lat: number, lng: number} | null>(null);
  const [loading, setLoading] = useState<boolean>(true);
  const [searching, setSearching] = useState<boolean>(false);
  const [result, setResult] = useState<RouteResult | null>(null);
  const [error, setError] = useState<string>("");

  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<L.Map | null>(null);
  const markersRef = useRef<L.Marker[]>([]);
  const routeLineRef = useRef<L.Polyline[]>([]);

  const GT_CENTER: [number, number] = [33.7756, -84.3963];

  // Custom marker icons -- same as before
  const startIcon = L.icon({ iconUrl: 'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-green.png', shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-shadow.png', iconSize: [25, 41], iconAnchor: [12, 41], popupAnchor: [1, -34], shadowSize: [41, 41] });
  const endIcon = L.icon({ iconUrl: 'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-red.png', shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-shadow.png', iconSize: [25, 41], iconAnchor: [12, 41], popupAnchor: [1, -34], shadowSize: [41, 41] });
  const transferIcon = L.icon({ iconUrl: 'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-orange.png', shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-shadow.png', iconSize: [25, 41], iconAnchor: [12, 41], popupAnchor: [1, -34], shadowSize: [41, 41] });
  const stopIcon = L.icon({ iconUrl: 'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-blue.png', shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-shadow.png', iconSize: [20, 33], iconAnchor: [10, 33], popupAnchor: [1, -28], shadowSize: [33, 33] });

  useEffect(() => {
    setRoutes(mockRoutes);
    // Gather all stops from all routes
    const allStops: Stop[] = [];
    const stopKey = new Set<string>(); // unique by id+name
    mockRoutes.forEach(route => {
      route.stops.forEach(stop => {
        const key = `${stop.id}|${stop.name}`;
        if (!stopKey.has(key)) {
          stopKey.add(key);
          allStops.push(stop);
        }
      });
    });
    setStops(allStops);
    setLoading(false);
  }, []);

  useEffect(() => {
    if (mapRef.current && !mapInstanceRef.current && stops.length > 0) initMap();
  }, [stops]);

  useEffect(() => {
    if (result && mapInstanceRef.current) updateMap();
  }, [result]);

  // --------- Utilities ----------
  function getStopByName(name: string): Stop | undefined {
    return stops.find(s => s.name === name);
  }
  function handleFromLocationSelect(e: React.ChangeEvent<HTMLSelectElement>) {
    const stopName = e.target.value;
    setFromLocation(stopName); // use name as canonical reference here
    const stop = getStopByName(stopName);
    if (stop) setFromCoords({ lat: stop.latitude, lng: stop.longitude });
  }
  function handleToLocationSelect(e: React.ChangeEvent<HTMLSelectElement>) {
    const stopName = e.target.value;
    setToLocation(stopName);
    const stop = getStopByName(stopName);
    if (stop) setToCoords({ lat: stop.latitude, lng: stop.longitude });
  }
  const calculateDistance = (lat1: number, lon1: number, lat2: number, lon2: number): number => {
    const toRadian = (angle: number) => (Math.PI / 180) * angle;
    const R = 6371;
    const dLat = toRadian(lat2 - lat1);
    const dLon = toRadian(lon2 - lon1);
    const a = Math.sin(dLat / 2) ** 2 +
      Math.cos(toRadian(lat1)) * Math.cos(toRadian(lat2)) *
      Math.sin(dLon / 2) ** 2;
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return R * c;
  };
  const clearMarkers = () => {
    if (!mapInstanceRef.current) return;
    markersRef.current.forEach(marker => {
      if (marker) mapInstanceRef.current!.removeLayer(marker);
    });
    markersRef.current = [];
    routeLineRef.current.forEach(line => { if (line) mapInstanceRef.current!.removeLayer(line); });
    routeLineRef.current = [];
  };
  const initMap = () => {
    if (!mapRef.current || mapInstanceRef.current) return;
    const map = L.map(mapRef.current).setView(GT_CENTER, 15);
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
      attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
    }).addTo(map);
    mapInstanceRef.current = map;
  };
  const updateMap = () => {
    if (!result || !mapInstanceRef.current) return;
    clearMarkers();
    const allCoordinates: [number, number][] = [];
    const colors = ['#3B82F6', '#10B981', '#8B5CF6', '#F59E0B', '#EC4899'];
    if (fromCoords) {
      allCoordinates.push([fromCoords.lat, fromCoords.lng]);
      markersRef.current.push(
        L.marker([fromCoords.lat, fromCoords.lng], { icon: startIcon })
          .bindPopup(`<strong>🏁 YOUR LOCATION</strong><br>${fromLocation}<br>Walk to ${result.startStop.name}`)
          .addTo(mapInstanceRef.current)
      );
      routeLineRef.current.push(
        L.polyline([
          [fromCoords.lat, fromCoords.lng],
          [result.startStop.latitude, result.startStop.longitude]
        ], { color: '#6B7280', weight: 3, opacity: 0.6, dashArray: '5, 10' }).addTo(mapInstanceRef.current)
      );
    }
    result.segments.forEach((segment, index) => {
      const coordinates: [number, number][] = segment.stops.map(s => [s.latitude, s.longitude]);
      allCoordinates.push(...coordinates);
      routeLineRef.current.push(
        L.polyline(coordinates, { color: colors[index % colors.length], weight: 4, opacity: 0.7 }).addTo(mapInstanceRef.current!)
      );
      segment.stops.forEach((stop, stopIndex) => {
        let icon = stopIcon;
        let popupText = `<strong>${stop.name}</strong>`;
        if (stopIndex === 0 && index > 0) {
          icon = transferIcon;
          popupText = `<strong>🔄 TRANSFER ${index}</strong><br>${stop.name}<br>Switch to ${segment.route.name}`;
        } else if (stopIndex === segment.stops.length - 1 && index < result.segments.length - 1) {
          icon = transferIcon;
          popupText = `<strong>🔄 TRANSFER ${index + 1}</strong><br>${stop.name}<br>Switch to ${result.segments[index + 1].route.name}`;
        }
        markersRef.current.push(L.marker([stop.latitude, stop.longitude], { icon }).bindPopup(popupText).addTo(mapInstanceRef.current!));
      });
    });
    if (toCoords) {
      allCoordinates.push([toCoords.lat, toCoords.lng]);
      markersRef.current.push(L.marker([toCoords.lat, toCoords.lng], { icon: endIcon })
        .bindPopup(`<strong>🎯 DESTINATION</strong><br>${toLocation}<br>Walk from ${result.endStop.name}`)
        .addTo(mapInstanceRef.current));
      routeLineRef.current.push(
        L.polyline([
          [result.endStop.latitude, result.endStop.longitude],
          [toCoords.lat, toCoords.lng]
        ], { color: '#6B7280', weight: 3, opacity: 0.6, dashArray: '5, 10' }).addTo(mapInstanceRef.current)
      );
    }
    if (allCoordinates.length > 0) {
      const bounds = L.latLngBounds(allCoordinates);
      mapInstanceRef.current.fitBounds(bounds, { padding: [50, 50] });
    }
  };

  // Robust hybrid-BFS transfer algorithm as above
  const findRouteWithBFS = (
    startStopId: string,
    endStopId: string
  ): Omit<RouteResult, 'startStop' | 'endStop' | 'walkingDistanceStart' | 'walkingDistanceEnd'> | null => {
    interface BFSNode {
      stopId: string;
      routeId: string;
      segments: RouteSegment[];
      transfers: number;
      visitedCombo: Set<string>;
    }
    const queue: BFSNode[] = [];
    const best: Record<string, number> = {};
    for (const route of routes) {
      for (let idx = 0; idx < route.stops.length; idx++) {
        if (route.stops[idx].id === startStopId) {
          queue.push({
            stopId: startStopId,
            routeId: route.id,
            segments: [],
            transfers: 0,
            visitedCombo: new Set([`${startStopId}:${route.id}`])
          });
          best[`${startStopId}:${route.id}`] = 0;
        }
      }
    }
    while (queue.length > 0) {
      const current = queue.shift()!;
      const route = routes.find(r => r.id === current.routeId);
      const curIdx = route?.stops.findIndex(s => s.id === current.stopId);
      if (!route || curIdx === undefined || curIdx < 0) continue;
      for (const dir of [-1, +1]) {
        let i = curIdx;
        while (i >= 0 && i < route.stops.length) {
          const stop = route.stops[i];
          if (stop.id === endStopId) {
            const segment: RouteSegment = {
              route,
              fromStop: route.stops[curIdx],
              toStop: stop,
              stops: route.stops.slice(
                Math.min(curIdx, i),
                Math.max(curIdx, i) + 1
              )
            };
            const allSegments = [...current.segments, segment];
            return {
              segments: allSegments,
              totalStops: allSegments.reduce((sum, seg) => sum + seg.stops.length, 0),
              transfers: allSegments.length - 1
            };
          }
          for (const otherRoute of routes) {
            if (otherRoute.id === route.id) continue;
            const transferIdx = otherRoute.stops.findIndex(s =>
              s.id === stop.id
            );
            if (transferIdx !== -1) {
              const key = `${stop.id}:${otherRoute.id}`;
              if (
                !current.visitedCombo.has(key) &&
                (best[key] === undefined || best[key] > current.transfers + 1)
              ) {
                const segment: RouteSegment = {
                  route,
                  fromStop: route.stops[curIdx],
                  toStop: stop,
                  stops: route.stops.slice(
                    Math.min(curIdx, i),
                    Math.max(curIdx, i) + 1
                  )
                };
                const newVisitedCombo = new Set(current.visitedCombo);
                newVisitedCombo.add(key);
                best[key] = current.transfers + 1;
                queue.push({
                  stopId: stop.id,
                  routeId: otherRoute.id,
                  segments: [...current.segments, segment],
                  transfers: current.transfers + 1,
                  visitedCombo: newVisitedCombo
                });
              }
            }
          }
          i += dir;
        }
      }
    }
    return null;
  };

  const findOptimalRoute = () => {
    if (!fromLocation || !toLocation) {
      setError("Please select both locations.");
      return;
    }
    if (fromLocation === toLocation) {
      setError("Starting location and destination cannot be the same.");
      return;
    }
    const fromStop = getStopByName(fromLocation);
    const toStop = getStopByName(toLocation);
    if (!fromStop || !toStop) {
      setError("Selected stop not found on the network.");
      return;
    }
    const walkDistStart = fromCoords ? calculateDistance(fromCoords.lat, fromCoords.lng, fromStop.latitude, fromStop.longitude) : 0;
    const walkDistEnd = toCoords ? calculateDistance(toCoords.lat, toCoords.lng, toStop.latitude, toStop.longitude) : 0;
    setSearching(true); setError(""); setResult(null);
    setTimeout(() => {
      const routeResult = findRouteWithBFS(fromStop.id, toStop.id);
      if (routeResult) {
        setResult({
          ...routeResult,
          startStop: fromStop,
          endStop: toStop,
          walkingDistanceStart: walkDistStart,
          walkingDistanceEnd: walkDistEnd
        });
      } else {
        setError("No routes found between these stops. Try a different combination.");
      }
      setSearching(false);
    }, 200);
  };

  if (loading) {
    return (
      <div className={styles.center}>
        <h2>🚌 Loading GT Bus Data...</h2>
      </div>
    );
  }

  return (
    <div className={styles.container}>
      <h1>🚌 Plan Your GT Trip</h1>
      <p>Enter your start and end locations—every stop is available for bus routing with transfers!</p>
      <div className={styles.gridContainer}>
        <div className={styles.formPanel}>
          <h2>Plan Your Route</h2>
          <div className={styles.form}>
            <label>🏁 Starting Location</label>
            <select value={fromLocation} onChange={handleFromLocationSelect} className={styles.select}>
              <option value="">Select starting stop</option>
              {stops.map(stop => (
                <option key={stop.id} value={stop.name}>{stop.name}</option>
              ))}
            </select>
            <label>🎯 Destination</label>
            <select value={toLocation} onChange={handleToLocationSelect} className={styles.select}>
              <option value="">Select destination</option>
              {stops.map(stop => (
                <option key={stop.id} value={stop.name}>{stop.name}</option>
              ))}
            </select>
            <button onClick={findOptimalRoute} disabled={searching}>
              {searching ? "Finding Route..." : "Find Best Route"}
            </button>
            {error && <p className={styles.error}>{error}</p>}
          </div>
          {result && (
            <div className={styles.result}>
              <h2>✅ Route Found</h2>
              <p className={styles.highlight}>
                {result.transfers === 0 ?
                  <>🚌 Direct route - No transfers needed!</> :
                  <>🔄 {result.transfers} transfer{result.transfers > 1 ? 's' : ''} required</>
                }
              </p>
              <div className={styles.walking}>
                <p>🚶 Walk {(result.walkingDistanceStart * 1000).toFixed(0)}m to <strong>{result.startStop.name}</strong></p>
              </div>
              {result.segments.map((segment, index) => (
                <div key={index} className={styles.segment}>
                  <h3>{index === 0 ? '🟢' : '🔄'} {segment.route.name}</h3>
                  <p>Board at: <strong>{segment.fromStop.name}</strong></p>
                  <p>Ride {segment.stops.length - 1} stop{segment.stops.length > 2 ? 's' : ''}</p>
                  <p>Exit at: <strong>{segment.toStop.name}</strong></p>
                  {index < result.segments.length - 1 && (
                    <p className={styles.transfer}>↓ Transfer to {result.segments[index + 1].route.name}</p>
                  )}
                </div>
              ))}
              <div className={styles.walking}>
                <p>🚶 Walk {(result.walkingDistanceEnd * 1000).toFixed(0)}m to destination</p>
              </div>
              <p className={styles.stats}>
                Total: {result.totalStops} bus stops + {((result.walkingDistanceStart + result.walkingDistanceEnd) * 1000).toFixed(0)}m walking
              </p>
            </div>
          )}
        </div>
        <div className={styles.mapPanel}>
          <div ref={mapRef} className={styles.map}></div>
        </div>
      </div>
      <Link to="/" className={styles.linkButton}>
        ← Return Home
      </Link>
    </div>
  );
};

export default PlanTripPage;
